def page(title, body):
    return f'<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{title}</title><style>{css}</style></head><body>{body}</body></html>'

def sticky(label='카톡 상담', second='전화 문의'):
    return f'<nav class="sticky"><a class="btn kakao" href="#">{label}</a><a class="btn dark" href="#">{second}</a></nav>'

